INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('8e1a51fa7ed7e123', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Does Pennsylvania allow any voter to vote by mail without an excuse?', '["No-excuse absentee voting","Act 77 mail voting rules","Can anyone get a mail ballot?"]', 'Yes. Under Act 77 of 2019, Pennsylvania established a no-excuse mail-in voting option, allowing any qualified registered voter to request and cast a mail-in ballot without providing a specific reason.', 'https://www.legis.state.pa.us/cfdocs/legis/li/uconsCheck.cfm?yr=2019&sessInd=0&act=77', 'Act 77 of 2019', '2026-05-10', 'static', 'statute_citation', 'Applies to all registered voters in Pennsylvania.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('abe81e924cf2d30f', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What is the ''naked ballot'' rule in Pennsylvania?', '["Secrecy envelope requirement","Will my mail ballot be rejected if it''s missing an envelope?","Naked ballot rejection"]', 'Pennsylvania law mandates that a mail-in or absentee ballot must be sealed within an inner ''secrecy envelope'' which is then placed inside the outer return envelope. Ballots returned without the inner secrecy envelope are deemed ''naked'' and are legally required to be rejected.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xiii-d/section-3146-8/', '25 P.S. § 3146.8(a) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all voters utilizing mail-in or absentee ballots.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('0774c56601d26028', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Do mail-in ballots have to be hand-dated by the voter?', '["Dating requirement on mail ballots","Will undated ballots be thrown out?","Envelope dating rules"]', 'Yes. The Pennsylvania Election Code requires the voter to fill out, date, and sign the declaration on the outer return envelope. The exact enforcement and rejection of undated or incorrectly dated ballots is highly litigated and subject to frequent court injunctions.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xiii-d/section-3146-6/', '25 P.S. § 3146.6(a) (Secondary/Justia)', '2026-05-10', 'volatile', 'secondary_source', 'Applies to all voters and county election boards.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('c77831a98b28a37f', 'PA', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Can Independent or minor party voters vote in the Republican primary?', '["Is Pennsylvania a closed primary state?","Can unaffiliated voters participate in the primary?","Party registration requirements"]', 'No. Pennsylvania is a strictly closed primary state. Only voters registered as a member of a specific political party (e.g., Republican or Democrat) by the registration deadline may vote for that party''s candidates in the primary election.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-viii/section-2812/', '25 P.S. § 2812 (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all voters participating in primary elections.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('67cd3051bd1b5d33', 'PA', '["federal","state","county","municipal","judicial"]', 'runoff_rules', 'Does Pennsylvania hold primary runoffs if no candidate gets 50%?', '["Primary runoff threshold","What happens in a crowded primary?","Do I need a majority to win the nomination?"]', 'No. Pennsylvania does not hold runoff elections. The candidate who receives the highest number of votes (a simple plurality) in the primary election becomes the party''s nominee, even if they do not secure a majority.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-ix/section-2882/', '25 P.S. § 2882 (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all partisan primary elections.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('9e101ac4f9820fe0', 'PA', '["state"]', 'election_dates', 'Is the Governor of Pennsylvania on the ballot in 2026?', '["2026 gubernatorial race","Is there a race for governor this cycle?","When do we elect the governor?"]', 'Yes. The Governor and Lieutenant Governor of Pennsylvania are elected to four-year terms in non-presidential even-numbered years. The next election for Governor is November 3, 2026.', 'https://www.legis.state.pa.us/cfdocs/legis/LI/consCheck.cfm?txtType=HTM&ttl=00&div=0&chpt=4&sctn=3', 'Constitution of Pennsylvania, Article IV, Section 3', '2026-05-10', 'static', 'statute_citation', 'Applies to candidate and voter awareness for the 2026 cycle.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('12c48c143f99abe0', 'PA', '["federal"]', 'election_dates', 'Is there a United States Senate race in Pennsylvania in 2026?', '["US Senate election PA 2026","Is Fetterman or Casey up for reelection?","Federal statewide races 2026"]', 'No. Pennsylvania''s Class 3 Senate seat (Fetterman) is up in 2028, and the Class 1 Senate seat (Casey) was up in 2024. Therefore, barring an unexpected special election, there is no regular U.S. Senate election in Pennsylvania in 2026.', 'https://www.pa.gov/agencies/vote/elections/upcoming-elections.html', 'Pennsylvania Department of State – Upcoming Elections', '2026-05-10', 'static', 'official_source_direct', 'Applies to candidate and voter awareness for the 2026 cycle.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('d845aecfeaea25d9', 'PA', '["federal","state","county","judicial"]', 'election_dates', 'When is the 2026 Primary Election in Pennsylvania?', '["PA primary date 2026","When do voters vote in the primary?","May primary date"]', 'In non-presidential years, the Pennsylvania primary election is statutorily held on the third Tuesday of May. For the 2026 cycle, this is Tuesday, May 19, 2026.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-vi/section-2753/', '25 P.S. § 2753(a) (Secondary/Justia)', '2026-05-10', 'per_cycle', 'secondary_source', 'Applies to all voters and candidates on the primary ballot.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('4eb12f17798a41a3', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'When is the 2026 General Election in Pennsylvania?', '["Election day 2026","What date is the November election?","Fall general election date"]', 'The 2026 General Election will be held on Tuesday, November 3, 2026.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-vi/section-2751/', '25 P.S. § 2751 (Secondary/Justia)', '2026-05-10', 'per_cycle', 'secondary_source', 'Applies to all voters and candidates.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('9dc543993106348f', 'PA', '["federal","state","county","judicial"]', 'ballot_access', 'When is the candidate filing period deadline for the 2026 primary?', '["When do I file for office?","Qualifying deadline 2026","Nomination petition deadline"]', 'Under Pennsylvania law, nomination petitions must be filed on or before the tenth Tuesday prior to the primary. For the May 19, 2026 primary, the filing deadline is Tuesday, March 10, 2026.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-ix/section-2873/', '25 P.S. § 2873(d) (Secondary/Justia)', '2026-05-10', 'per_cycle', 'secondary_source', 'Applies to partisan candidates seeking primary ballot access.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('c37729694716ab43', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can a corporation or labor union donate directly to my campaign?', '["Are corporate contributions legal?","Can a business write a campaign check?","Corporate donation ban"]', 'No. Pennsylvania explicitly prohibits national banks, corporations, and unincorporated associations (like labor unions) from making any direct contribution or expenditure to a political candidate''s campaign.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xvi/section-3253/', '25 P.S. § 3253(a) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to candidate campaigns and business/union entities.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('ca3acf9b8d8bc93a', 'PA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the maximum individual contribution limit for a state or local candidate?', '["How much can one person donate?","Maximum campaign contribution cap","Individual donor limits"]', 'Pennsylvania has NO contribution limits for individuals donating to state and local candidates. An individual may contribute an unlimited amount to a candidate, provided it is properly reported.', 'https://www.dos.pa.gov/VotingElections/CandidatesCommittees/CampaignFinance/Pages/default.aspx', 'Pennsylvania Department of State – Campaign Finance', '2026-05-10', 'static', 'official_source_direct', 'Applies to individuals donating to Pennsylvania campaigns.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('addc48818fefdae4', 'PA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'How much can a PAC donate to a state or local campaign?', '["PAC contribution limits","Political committee donation caps","Do PACs have giving limits?"]', 'Pennsylvania has NO contribution limits for Political Action Committees (PACs) donating to state and local candidates. PACs may contribute unlimited amounts, provided the contributions are properly reported.', 'https://www.dos.pa.gov/VotingElections/CandidatesCommittees/CampaignFinance/Pages/default.aspx', 'Pennsylvania Department of State – Campaign Finance', '2026-05-10', 'static', 'official_source_direct', 'Applies to PACs donating to state and local campaigns.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('e3762785b1aaf481', 'PA', '["judicial"]', 'election_dates', 'How are judges elected in Pennsylvania?', '["Judicial election dates","Are judges on the ballot?","Partisan judicial elections"]', 'Pennsylvania initially elects all judges (Supreme Court, Superior Court, Commonwealth Court, and Common Pleas) via partisan elections held in odd-numbered years. After serving their initial 10-year term, they face a nonpartisan retention (Yes/No) election.', 'https://www.legis.state.pa.us/cfdocs/legis/LI/consCheck.cfm?txtType=HTM&ttl=00&div=0&chpt=5&sctn=13', 'Constitution of Pennsylvania, Article V, Section 13 & Section 15', '2026-05-10', 'static', 'statute_citation', 'Applies to the selection of Pennsylvania state judges.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('a276ba4d6853c30c', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Is photo ID required to vote in person in Pennsylvania?', '["Voter ID rules","Voting without a driver''s license","First time voter ID requirement"]', 'No. A voter does not need to show ID every time they vote. However, under state law, an individual who is voting for the FIRST time at a specific polling place must show an approved form of ID (which can be a photo ID or a non-photo ID like a utility bill).', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xii/section-3050/', '25 P.S. § 3050(b) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all in-person voters.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('e19a133b7e14f899', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'When is the deadline to return a mail-in ballot?', '["Absentee return deadline","How late can an absentee ballot arrive?","Does postmark matter for mail ballots?"]', 'A mail-in or civilian absentee ballot must be physically received by the county election office no later than 8:00 p.m. on Election Day. A postmark is not sufficient; ballots arriving after 8:00 p.m. are rejected.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xiii-d/section-3146-6/', '25 P.S. § 3146.6(a) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to domestic civilian voters returning mail ballots.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('e004ccf67febdf14', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'When is the deadline to request a mail-in ballot?', '["Last day to ask for a mail ballot","Cutoff to request absentee","Mail ballot request deadline"]', 'An application requesting a mail-in or absentee ballot must be received by the county election office no later than 5:00 p.m. on the Tuesday before the election (exactly 7 days prior). For the May 19, 2026 primary, this is 5:00 PM on May 12, 2026.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xiii-d/section-3150-12a/', '25 P.S. § 3150.12a(a) (Secondary/Justia)', '2026-05-10', 'per_cycle', 'secondary_source', 'Applies to voters requiring absentee-by-mail ballots.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('aae12a4c06625e82', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What is the standard voter registration deadline?', '["When do the voter registration books close?","Registration cutoff date","Last day to register to vote"]', 'The deadline to register to vote or update a registration in Pennsylvania is 15 days before the election. For the May 19, 2026 primary, the deadline is Monday, May 4, 2026.', 'https://www.legis.state.pa.us/cfdocs/legis/LI/consCheck.cfm?txtType=HTM&ttl=25&div=0&chpt=13&sctn=26', '25 Pa.C.S. § 1326', '2026-05-10', 'static', 'statute_citation', 'Applies to all unregistered eligible voters.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('0f9061d161ecda7c', 'PA', '["state","county","municipal","special_district"]', 'recall_rules', 'Can an elected official be recalled from office by voters in Pennsylvania?', '["How do we recall a governor?","Recall election procedures","Removing an official early"]', 'Pennsylvania has NO statewide recall mechanism for state-level officials. While a small number of Home Rule charter municipalities (like Philadelphia) have local charter-based recall provisions, standard state and county officials cannot be recalled via ballot petition.', 'https://www.legis.state.pa.us/cfdocs/legis/LI/consCheck.cfm?txtType=HTM&ttl=00&div=0&chpt=6', 'Constitution of Pennsylvania, Article VI (Context)', '2026-05-10', 'static', 'statute_citation', 'Applies to voters inquiring about recalling elected officials.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('e793660f37f15002', 'PA', '["federal","state","county","municipal"]', 'ballot_access', 'How is the filing fee calculated to run for office?', '["How much is the qualifying fee?","Calculation of the filing cost","Base rate for candidate fees"]', 'Pennsylvania uses specific statutory dollar amounts for filing fees, rather than a percentage of salary. For example, the fee is $200 for U.S. Senate, $150 for U.S. House, and $100 for State Senate, State House, or local county offices.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-ix/section-2873/', '25 P.S. § 2873(b) (Secondary/Justia)', '2026-05-10', 'per_cycle', 'secondary_source', 'Applies to all candidates paying a monetary fee for ballot access.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('ab0572bbcdd88b0a', 'PA', '["state","county","municipal","judicial"]', 'finance_ethics', 'Do I have to file a Statement of Financial Interests to get on the ballot?', '["Ethics paperwork for candidates","When do I file financial disclosures?","State Ethics Commission forms"]', 'Yes. A candidate for state or local office must file a Statement of Financial Interests with the State Ethics Commission on or before the last day for filing a petition to appear on the ballot. A copy must also be appended to the nomination petition.', 'https://www.legis.state.pa.us/cfdocs/legis/LI/consCheck.cfm?txtType=HTM&ttl=65&div=0&chpt=11&sctn=4', '65 Pa.C.S. § 1104(b)', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates required to file ethics disclosures.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('dca435dfac43aa44', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'How far from the polling place entrance must campaign volunteers stay?', '["Electioneering distance rules","Where can we hold signs at the polls?","Buffer zone restrictions"]', 'Under Pennsylvania law, campaign workers and electioneers must remain at least 10 feet distant from the polling place (the room where voting occurs). In practice, building entrance layouts often extend this functionally, but the legal boundary is 10 feet.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xii/section-3060/', '25 P.S. § 3060(d) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all campaign volunteers and electioneers.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('b7399c6a0eff2820', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Are absentee ballot drop boxes allowed in Pennsylvania?', '["Where are the drop boxes?","Can I drop off my mail ballot?","Drop box availability rules"]', 'Yes, but they are entirely subject to county discretion. Following a Pennsylvania Supreme Court ruling under Act 77, county boards of elections are legally permitted to deploy secure drop boxes, but they are not required to do so. Availability varies wildly by county.', 'https://www.vote.pa.gov/Voting-in-PA/Pages/Drop-Box.aspx', 'Pennsylvania Voter Portal – Drop Box Information', '2026-05-10', 'volatile', 'official_source_direct', 'Applies to voters returning mail ballots and county election officials.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('4f6337781b603823', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'Does Pennsylvania have early in-person voting?', '["When does early voting start?","In-person early voting dates","Duration of early voting window"]', 'Pennsylvania does not have traditional machine early voting. Instead, voters may request, receive, fill out, and submit a mail-in ballot in person at their county election office in a single visit, starting once ballots are finalized (usually a few weeks before the election).', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xiii-d/section-3150-12a/', '25 P.S. § 3150.12a(a) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all voters seeking to cast a ballot before Election Day.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('b78edc7d9b57b4a9', 'PA', '["federal","state","county","municipal","judicial"]', 'candidate_eligibility', 'Do I have to live in the district to run for U.S. House in Pennsylvania?', '["Federal residency rules","Can I run for Congress if I don''t live in the district?","US House eligibility"]', 'No. A candidate for the U.S. House must be at least 25 years old, a citizen for 7 years, and an ''inhabitant'' of Pennsylvania when elected. The U.S. Constitution does not require the candidate to legally reside within the specific boundaries of the congressional district.', 'https://www.dos.pa.gov/VotingElections/CandidatesCommittees/RunningforOffice/Pages/default.aspx', 'Pennsylvania Department of State – Running for Office', '2026-05-10', 'static', 'official_source_direct', 'Applies to candidates for the United States House of Representatives.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('328f14204cbf3797', 'PA', '["state"]', 'election_dates', 'Which Pennsylvania State Senate seats are on the ballot in 2026?', '["PA Senate staggered terms","Are all state senators elected at once?","2026 state senate districts"]', 'Pennsylvania has 50 State Senate seats with staggered four-year terms. In the 2026 cycle (a gubernatorial election year), all 25 even-numbered Senate districts are up for election.', 'https://www.legis.state.pa.us/cfdocs/legis/LI/consCheck.cfm?txtType=HTM&ttl=00&div=0&chpt=2&sctn=3', 'Constitution of Pennsylvania, Article II, Section 3', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates for the Pennsylvania State Senate.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('93acfb6cd037d8bc', 'PA', '["federal"]', 'election_dates', 'Are all of Pennsylvania''s U.S. House seats on the ballot in 2026?', '["How many congressional districts are up in 2026?","US House election cycle PA","2026 congressional races"]', 'Yes. All 17 of Pennsylvania''s U.S. House of Representatives seats serve two-year terms and will be on the 2026 ballot.', 'https://www.dos.pa.gov/VotingElections/CandidatesCommittees/RunningforOffice/Pages/default.aspx', 'Pennsylvania Department of State – Running for Office', '2026-05-10', 'static', 'official_source_direct', 'Applies to candidates for the U.S. House of Representatives.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('983b875ecc8afe89', 'PA', '["state"]', 'election_dates', 'Are all Pennsylvania State House seats on the ballot in 2026?', '["How many state rep seats are up?","PA House of Representatives cycle","2026 state house elections"]', 'Yes. All 203 seats in the Pennsylvania House of Representatives serve two-year terms and are on the ballot for the 2026 election cycle.', 'https://www.legis.state.pa.us/cfdocs/legis/LI/consCheck.cfm?txtType=HTM&ttl=00&div=0&chpt=2&sctn=3', 'Constitution of Pennsylvania, Article II, Section 3', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates for the Pennsylvania House of Representatives.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('f26285f82c04853e', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'election_dates', 'What is the exact voter registration deadline for the 2026 General Election?', '["When do the books close for November?","Registration cutoff date for the general election","Last day to register to vote for fall 2026"]', 'The registration deadline is 15 days before the election. For the November 3, 2026 general election, the deadline is Monday, October 19, 2026.', 'https://www.legis.state.pa.us/cfdocs/legis/LI/consCheck.cfm?txtType=HTM&ttl=25&div=0&chpt=13&sctn=26', '25 Pa.C.S. § 1326', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to unregistered eligible voters seeking to vote in the general.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('7ebed8d12c647c13', 'PA', '["federal","state"]', 'ballot_access', 'How many petition signatures does a major party candidate need to run for U.S. Senate or Governor?', '["Primary signature requirement for Senate","How many signatures to run for Governor?","Statewide major party petition threshold"]', 'To qualify for the primary ballot, a major party candidate for U.S. Senate or Governor must gather 2,000 valid signatures from registered voters of their own party, including at least 100 signatures from each of at least 10 different counties.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-ix/section-2872-1/', '25 P.S. § 2872.1(3) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to major party candidates for statewide office.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('479248e37b8a0643', 'PA', '["federal"]', 'ballot_access', 'How many petition signatures does a major party candidate need to run for U.S. House?', '["Primary signature requirement for Congress","How many signatures for US Rep?","Congressional district petition threshold"]', 'To qualify for the primary ballot, a major party candidate for the U.S. House of Representatives must gather 1,000 valid signatures from registered voters of their own party within that specific congressional district.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-ix/section-2872-1/', '25 P.S. § 2872.1(12) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to major party candidates for the U.S. House.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('1c09871d46511b54', 'PA', '["state"]', 'ballot_access', 'How many petition signatures does a major party candidate need to run for State Senate or State House?', '["Primary signature requirement for legislature","How many signatures for state rep?","General Assembly petition threshold"]', 'To qualify for the primary ballot, a major party candidate must gather 500 valid signatures for the State Senate, and 300 valid signatures for the State House of Representatives, collected from voters of their party within the district.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-ix/section-2872-1/', '25 P.S. § 2872.1(13-14) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to major party candidates for the Pennsylvania General Assembly.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('29b526c3185ad91c', 'PA', '["federal","state","county","municipal"]', 'ballot_access', 'How many signatures do independent or minor party candidates need to get on the ballot?', '["Independent candidate petition rules","Minor party signature threshold","Avoiding the party primary"]', 'Independent and minor party candidates face a massive barrier: they must gather signatures equal to 2% of the largest entire vote cast for any elected candidate in the last statewide election. This routinely translates to a requirement of tens of thousands of signatures.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-ix/section-2911/', '25 P.S. § 2911(b) (Secondary/Justia)', '2026-05-10', 'volatile', 'secondary_source', 'Applies to independent and minor political body candidates.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('6ed5f47ffc1bd9f8', 'PA', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'What is the deadline to file a legal challenge against a candidate''s petition signatures?', '["Petition challenge timing","How long do I have to sue to knock someone off the ballot?","Objecting to nomination papers"]', 'A petition to set aside a candidate''s nomination petition (a ballot challenge) must be filed with the Commonwealth Court within seven (7) days after the final statutory deadline for filing the nomination petition.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-ix/section-2937/', '25 P.S. § 2937 (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to campaigns challenging an opponent''s ballot access.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('24c9808da489cd4c', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the standard campaign finance reporting schedule in Pennsylvania?', '["How often do I file finance reports?","Election code reporting cycles","When are my disclosure reports due?"]', 'Committees active in an election must file reports at specific pre- and post-election intervals: a 6th Tuesday Pre-Election, a 2nd Friday Pre-Election, and a 30-Day Post-Election report for BOTH the primary and general elections, plus an Annual Report due January 31.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xvi/section-3246/', '25 P.S. § 3246(b)-(e) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all active campaign committees.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('3ad24a320f20ff04', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What paperwork is required to officially organize my campaign committee?', '["How do I start raising money?","Political committee registration","Opening a campaign account"]', 'Before receiving any contributions or making any expenditures, a political committee must file a Political Committee Registration Statement identifying its chairperson and treasurer with the appropriate election bureau.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xvi/section-3243/', '25 P.S. § 3243(a) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all newly formed campaign committees.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('efa5a77ae8d22f09', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I raise money if my campaign doesn''t have a treasurer?', '["Do I need a treasurer before I raise money?","Vacant treasurer office rules","Can the candidate act as treasurer?"]', 'No. Under Pennsylvania law, no contribution can be received or expenditure made by a political committee at any time when there is a vacancy in the office of treasurer or chairperson.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xvi/section-3242/', '25 P.S. § 3242(a) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all campaign committees.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('001500ad1cc7fd82', 'PA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'How do I report an in-kind contribution?', '["In-kind valuation","How much is a donated venue worth?","Reporting free services"]', 'In-kind contributions (such as donated food or services) must be reported at their fair market value. Even though there are no contribution limits in Pennsylvania, these must be fully disclosed as both a receipt and an expenditure.', 'https://www.dos.pa.gov/VotingElections/CandidatesCommittees/CampaignFinance/Documents/Campaign-Finance-Reporting-Law.pdf', 'Pennsylvania Department of State – Campaign Finance Guide', '2026-05-10', 'static', 'official_source_direct', 'Applies to all campaigns accepting non-monetary donations.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('04fa278d323fb841', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'When does a third party have to report an Independent Expenditure?', '["IE reporting threshold","When do independent groups have to disclose?","Threshold for third-party reporting"]', 'Any person making an independent expenditure of $100 or more to expressly advocate for the election or defeat of a candidate must file an independent expenditure report with the state or county.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xvi/section-3246/', '25 P.S. § 3246(g) (Secondary/Justia)', '2026-05-10', 'per_cycle', 'secondary_source', 'Applies to individuals and groups making political expenditures without coordination.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('4fcc77341cf42ec7', 'PA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the 24-hour reporting rule for late contributions?', '["Late fee for large pre-election donations","Penalty for missing the 24-hour report","Fines for late big checks"]', 'Any contribution or pledge of $500 or more received after the final pre-election report has been filed, but before the election itself, must be reported to the Department of State or County Board of Elections within 24 hours of receipt. This $500 threshold applies uniformly to all state and local candidates.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xvi/section-3248/', '25 P.S. § 3248 (Secondary/Justia)', '2026-05-10', 'per_cycle', 'secondary_source', 'Applies to all campaigns receiving large late contributions.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('816d3f67bd942f3f', 'PA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can I use campaign funds to pay my personal mortgage or buy groceries?', '["Personal use of campaign funds","Can I pay rent with donor money?","Impermissible uses of campaign cash"]', 'No. Pennsylvania explicitly prohibits the personal use of campaign funds. Funds must be used exclusively for influencing the outcome of an election or for expenses related to holding public office.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xvi/section-3254-1/', '25 P.S. § 3254.1 (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all candidates and officeholders.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('e08cb1aeb2c8260c', 'PA', '["state"]', 'residency', 'What are the residency and age requirements to run for Governor of Pennsylvania?', '["How old to run for governor?","Residency rules for statewide office","Qualifications for governor"]', 'A candidate for Governor or Lieutenant Governor must be a citizen of the United States, at least 30 years old, and a resident of Pennsylvania for at least seven (7) years preceding the election.', 'https://www.legis.state.pa.us/cfdocs/legis/LI/consCheck.cfm?txtType=HTM&ttl=00&div=0&chpt=4&sctn=5', 'Constitution of Pennsylvania, Article IV, Section 5', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates for Governor and Lieutenant Governor.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('766cbc241a754614', 'PA', '["state"]', 'residency', 'What are the residency and age requirements to run for the Pennsylvania State Legislature?', '["How old to run for state house?","Residency rules for state senate","District residency timeline"]', 'State Senators must be 25 years old, and State Representatives 21. Both must be citizens and inhabitants of Pennsylvania for four (4) years, and inhabitants of their respective districts for one (1) year prior to the election.', 'https://www.legis.state.pa.us/cfdocs/legis/LI/consCheck.cfm?txtType=HTM&ttl=00&div=0&chpt=2&sctn=5', 'Constitution of Pennsylvania, Article II, Section 5', '2026-05-10', 'static', 'statute_citation', 'Applies to candidates for the Pennsylvania General Assembly.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('0db6f7477dda095f', 'PA', '["state","county","municipal","judicial"]', 'finance_ethics', 'What financial information must be disclosed on the Statement of Financial Interests (SFI)?', '["What is on the SFI?","Do I have to disclose my debts?","Reporting real estate on ethics forms"]', 'The SFI requires candidates to disclose real estate interests, creditors owed over $6,500, direct or indirect sources of income over $1,300, and gifts valued at $250 or more.', 'https://www.legis.state.pa.us/cfdocs/legis/LI/consCheck.cfm?txtType=HTM&ttl=65&div=0&chpt=11&sctn=5', '65 Pa.C.S. § 1105(b)', '2026-05-10', 'per_cycle', 'statute_citation', 'Applies to candidates required to file the SFI.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('63033df527c4f86a', 'PA', '["state","county","municipal","judicial"]', 'ballot_access', 'What happens if I forget to file my Statement of Financial Interests by the petition deadline?', '["Missing the ethics filing deadline","Penalty for late SFI","Can I file my financial disclosure late?"]', 'Failing to file the Statement of Financial Interests with the State Ethics Commission by the petition filing deadline is considered a ''fatal defect'' under state law, resulting in the candidate being automatically struck from the ballot.', 'https://www.legis.state.pa.us/cfdocs/legis/LI/consCheck.cfm?txtType=HTM&ttl=65&div=0&chpt=11&sctn=4', '65 Pa.C.S. § 1104(b)(3)', '2026-05-10', 'static', 'statute_citation', 'Applies to all candidates required to file an SFI.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('e91972c981fbc09c', 'PA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Does my campaign bank account have to be at a Pennsylvania bank?', '["Campaign depository rules","Can I use an out-of-state bank?","Where can I open my campaign account?"]', 'Every political committee must maintain a single designated campaign depository (bank account) in a State or National bank authorized to do business in Pennsylvania. Commingling campaign funds with personal funds is strictly prohibited.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xvi/section-3242/', '25 P.S. § 3242(h) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all campaign treasurers establishing accounts.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('d243a93a82bc123a', 'PA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Do I have to file detailed quarterly reports if my campaign spends very little money?', '["Under threshold reporting","Short form campaign finance","Exemption from full reports"]', 'Candidates or committees that do not intend to receive or expend more than $250 during a reporting period may file a sworn affidavit to that effect (a short form) in lieu of filing the detailed, itemized campaign finance report.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xvi/section-3246/', '25 P.S. § 3246(a) (Secondary/Justia)', '2026-05-10', 'per_cycle', 'secondary_source', 'Applies to candidates running low-budget campaigns.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('217db63110494fd4', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'How long must my campaign treasurer keep our financial records?', '["Record retention rules","How long do I save receipts?","Keeping finance reports post-election"]', 'Campaign treasurers and candidates must retain all records, accounts, vouchers, and receipts related to the campaign for a period of three (3) years after the information is reported.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xvi/section-3242/', '25 P.S. § 3242(c) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all campaign treasurers and candidates.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('d805b58861af0140', 'PA', '["state","county","municipal"]', 'finance_ethics', 'Where do I file my campaign finance reports?', '["Do I report to the state or county?","Filing locations","Submitting ethics paperwork"]', 'Statewide candidates and candidates for the General Assembly file their reports with the Secretary of the Commonwealth (Department of State). Local candidates (county, municipal) file exclusively with their respective County Board of Elections.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xvi/section-3249/', '25 P.S. § 3249 (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all candidates filing finance reports.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('53a01477b1b66b05', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Who is legally allowed to serve as a poll watcher in Pennsylvania?', '["Poll watcher qualifications","Can I bring in observers from out of state?","Who can be an election observer?"]', 'A poll watcher in Pennsylvania MUST be a qualified, registered elector (voter) of the specific county in which the election district for which they are appointed is located.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-iv/section-2687/', '25 P.S. § 2687(b) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to campaigns appointing election observers.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('9a2ea8824a596a48', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'What happens if a voter''s eligibility is challenged at the polling place?', '["Challenged voter rules","Provisional ballot trigger","What if someone says I can''t vote?"]', 'If a voter''s identity or residency is challenged by a poll watcher or election officer, the voter is legally entitled to cast a provisional ballot, which will be evaluated by the county board of elections during the canvass.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xii/section-3050/', '25 P.S. § 3050(a.4)(1) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to voters facing eligibility challenges on Election Day.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('59ebbd41f4a69cf9', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Are campaign signs allowed to be placed on the state highway right-of-way?', '["Can I put signs in the median?","Highway campaign sign rules","Does PennDOT take down political signs?"]', 'No. Pennsylvania law (the Outdoor Advertising Control Act) generally prohibits the placement of unauthorized signs, including political campaign signs, within the right-of-way of any state highway.', 'https://www.pacodeandbulletin.gov/Display/pacode?file=/secure/pacode/data/067/chapter445/s445.4.html', '67 Pa. Code § 445.4(b)(2)', '2026-05-10', 'static', 'statute_citation', 'Applies to all campaigns placing signage.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('4d42832b226e8e13', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What are the disclaimer rules for campaign robocalls?', '["Robocall rules","Voice call political advertising","Do auto-dialers need to say who paid for it?"]', 'Under Pennsylvania law, any broadcast or telephonic communication (including robocalls) that expressly advocates for a candidate must clearly state who paid for or authorized the communication.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xvi/section-3258/', '25 P.S. § 3258(a) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all campaigns conducting phone outreach.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('f6eddbd1f43aba15', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Do SMS text messages sent to voters require a political disclaimer?', '["Text messaging campaign rules","Do campaign texts need disclaimers?","Mass texting disclosure"]', 'Yes. Campaign text messages fall under general political advertising regulations. Mass texts must include a ''Paid for by'' sponsorship legend, either directly in the text or via a clear, prominent link.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xvi/section-3258/', '25 P.S. § 3258 (Context) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all campaigns using mass SMS.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('52fc8324ca017ed5', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Does my campaign website or digital ad require a ''Paid for by'' disclaimer?', '["Digital advertising disclaimers","Do Facebook ads need disclosures?","Website paid-for rules"]', 'Yes. Any communication published on the internet or distributed via digital advertising platforms (like Facebook or Google) must include a clear disclosure stating who paid for or authorized the communication.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xvi/section-3258/', '25 P.S. § 3258(a) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all campaigns running digital advertisements.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('a99dbe9d1e36c9e7', 'PA', '["federal","state","county","municipal","judicial"]', 'ballot_access', 'What happens if a candidate dies or withdraws after the primary but before the general election?', '["Vacancy after qualifying","Replacing a dead candidate","Nominee replacement procedure"]', 'If a nominated candidate dies or withdraws, the appropriate political party committee (state, county, or district level) is legally authorized to appoint a substitute nominee to fill the vacancy on the general election ballot.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-ix/section-2939/', '25 P.S. § 2939 (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to party committees filling a vacancy on the ballot.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('e13ae71dbe0510a7', 'PA', '["state","county","municipal"]', 'finance_ethics', 'Can I use campaign funds to pay for legal defense?', '["Paying lawyers with donor money","Are legal fees a campaign expense?","Defending against ethics complaints"]', 'Yes. Campaign funds may generally be used to pay for attorney''s fees and legal costs if the legal action arises directly out of the campaign or the execution of the candidate''s official duties.', 'https://www.dos.pa.gov/VotingElections/CandidatesCommittees/CampaignFinance/Documents/Campaign-Finance-Reporting-Law.pdf', 'Pennsylvania Department of State – Campaign Finance Guide', '2026-05-10', 'static', 'official_source_direct', 'Applies to candidates facing legal or ethics challenges.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('6f607e396b64d822', 'PA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Does Pennsylvania require candidates to open a separate ''Officeholder Account'' after they win?', '["Officeholder account rules","Do I need a new bank account once elected?","Keeping the campaign account open"]', 'No. Pennsylvania does not require a separate ''officeholder account.'' An elected official may retain their campaign committee and use surplus funds for expenses directly related to the holding of public office.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xvi/section-3254-1/', '25 P.S. § 3254.1 (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to successful candidates transitioning to officeholders.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('9349b1c896bf27e5', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'finance_ethics', 'Can my campaign accept donations from foreign nationals?', '["Accepting money from non-citizens","Foreign contributions in PA","Can someone from overseas donate?"]', 'No. Federal law strictly prohibits foreign nationals from directly or indirectly making contributions or donations of money or other things of value in connection with ANY federal, state, or local election.', 'https://www.fec.gov/help-candidates-and-committees/candidate-taking-receipts/who-can-and-cant-contribute/', 'Federal Election Commission (Federal Preemption)', '2026-05-10', 'static', 'official_source_direct', 'Applies to all campaigns and political committees.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('f43bf9a7e1bc1713', 'PA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'How do I officially close my campaign account after the election?', '["Ending my campaign reporting obligations","Filing the termination report","How to stop filing ethics reports"]', 'To end reporting obligations, a candidate must file a ''Termination Report'' (marking the termination box on the standard form) showing a zero cash balance, no outstanding debts or obligations, and confirming all surplus funds are disposed of.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xvi/section-3246/', '25 P.S. § 3246(a) (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to all candidates wishing to terminate their campaign treasurer appointment.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('a8b589b52e010a84', 'PA', '["state","county","municipal","judicial"]', 'candidate_eligibility', 'Can an individual with a felony conviction run for office in Pennsylvania?', '["Felon running for office","Does a conviction disqualify me?","Candidate background checks"]', 'Article II, Section 7 of the Pennsylvania Constitution explicitly prohibits any person convicted of ''embezzlement of public moneys, bribery, perjury or other infamous crime'' from serving in the General Assembly or holding any office of trust or profit in the Commonwealth.', 'https://www.legis.state.pa.us/cfdocs/legis/LI/consCheck.cfm?txtType=HTM&ttl=00&div=0&chpt=2&sctn=7', 'Constitution of Pennsylvania, Article II, Section 7', '2026-05-10', 'static', 'statute_citation', 'Applies to individuals with severe criminal convictions seeking office.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('d184798d922a6d8d', 'PA', '["federal","state","county","municipal","judicial","special_district"]', 'voter_interaction', 'Can an individual with a felony conviction vote in Pennsylvania?', '["Felony voting rights","Can felons vote after prison?","Restoration of rights in PA"]', 'Yes. In Pennsylvania, an individual with a felony conviction automatically regains their right to vote immediately upon release from a correctional facility (prison/jail). They may vote even while actively on probation or parole.', 'https://www.vote.pa.gov/Register-to-Vote/Pages/Convicted-Felon-Brochure.aspx', 'Pennsylvania Voter Portal – Voting Rights for Convicted Felons', '2026-05-10', 'static', 'official_source_direct', 'Applies to Pennsylvania residents with past felony convictions.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('bfaede8d81bffd19', 'PA', '["federal","state"]', 'redistricting', 'What is the status of the congressional and state legislative maps for the 2026 cycle?', '["Current redistricting map","Did the court change the district lines?","LRC map status"]', 'The congressional maps drawn by the Pennsylvania Supreme Court in 2022 (Carter v. Chapman), and the state legislative maps drawn by the Legislative Reapportionment Commission (LRC), remain the legally active maps for the 2026 cycle.', 'https://www.dos.pa.gov/VotingElections/Pages/Redistricting.aspx', 'Pennsylvania Department of State – Redistricting', '2026-05-10', 'static', 'official_source_direct', 'Applies to all candidates and voters navigating district boundaries.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('a0a24b4c070374f0', 'PA', '["state","county","municipal","judicial","special_district"]', 'finance_ethics', 'What is the penalty for filing a campaign finance report late?', '["How much are late fees for ethics reports?","Fines for missing a deadline","Bureau of Elections penalties"]', 'Pennsylvania assesses a late filing fee of $10 for each late day for the first six days, and $20 for each late day thereafter, up to a maximum penalty of $250 per report.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-xvi/section-3252/', '25 P.S. § 3252(a) (Secondary/Justia)', '2026-05-10', 'per_cycle', 'secondary_source', 'Applies to all candidates failing to file disclosure reports on time.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1'),
  ('821633b04ff36b23', 'PA', '["state","county"]', 'election_dates', 'When does the Speaker of the House schedule a special election for a vacant seat?', '["Special election timing","Writ of election for state rep","Filling a vacancy in the general assembly"]', 'When a vacancy occurs in either house of the General Assembly, the presiding officer (e.g., the Speaker) issues a writ of election. The special election must be scheduled on a date not less than 60 days after the issuance of the writ.', 'https://law.justia.com/codes/pennsylvania/title-25/chapter-14/article-vi/section-2778/', '25 P.S. § 2778 (Secondary/Justia)', '2026-05-10', 'static', 'secondary_source', 'Applies to candidates seeking to fill legislative vacancies.', 'batch_2026-05-10T20-42-43_pennsylvania_full_v1')
